import React, { useState, useMemo, useCallback } from 'react';

const SYMBOLS = ['🍎', '🚀', '🎲', '🎸', '🌵', '⚓'];

function shuffle(arr) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function makeDeck() {
  return shuffle([...SYMBOLS, ...SYMBOLS]).map((s, i) => ({ id: i, s }));
}

export default function MemoryGame() {
  const [deck, setDeck] = useState(makeDeck);
  const [flipped, setFlipped] = useState([]);
  const [matched, setMatched] = useState(() => new Set());
  const [lock, setLock] = useState(false);
  const [moves, setMoves] = useState(0);

  const flip = useCallback(
    (i) => {
      if (lock || flipped.includes(i) || matched.has(i)) return;
      const next = [...flipped, i];
      setFlipped(next);
      if (next.length === 2) {
        setMoves((m) => m + 1);
        const [a, b] = next;
        if (deck[a].s === deck[b].s) {
          setMatched((m) => new Set([...m, a, b]));
          setFlipped([]);
        } else {
          setLock(true);
          setTimeout(() => {
            setFlipped([]);
            setLock(false);
          }, 800);
        }
      }
    },
    [lock, flipped, matched, deck]
  );

  const reset = () => {
    setDeck(makeDeck());
    setFlipped([]);
    setMatched(new Set());
    setLock(false);
    setMoves(0);
  };

  const won = matched.size === deck.length;

  return (
    <div>
      <p style={{ fontWeight: 600 }}>
        Moves: {moves} {won && '— You win! 🎉'}
      </p>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 64px)', gap: 8 }}>
        {deck.map((card, i) => {
          const up = flipped.includes(i) || matched.has(i);
          return (
            <button
              key={card.id}
              onClick={() => flip(i)}
              style={{ width: 64, height: 64, fontSize: 28, cursor: 'pointer', borderRadius: 8, border: '1px solid #cbd5e1', background: up ? '#fff' : '#2563eb', color: up ? '#111' : 'transparent' }}
            >
              {up ? card.s : '?'}
            </button>
          );
        })}
      </div>
      <button onClick={reset} style={{ marginTop: 14, padding: '8px 16px', cursor: 'pointer' }}>New game</button>
    </div>
  );
}

