import { Component } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Card { id: number; s: string; }

@Component({
  selector: 'app-memory-game',
  template: `
    <div>
      <p style="font-weight: 600;">Moves: {{ moves }} <span *ngIf="won">— You win! 🎉</span></p>
      <div style="display: grid; grid-template-columns: repeat(4, 64px); gap: 8px;">
        <button
          *ngFor="let card of deck; let i = index"
          (click)="flip(i)"
          [style.background]="isUp(i) ? '#fff' : '#2563eb'"
          [style.color]="isUp(i) ? '#111' : 'transparent'"
          style="width: 64px; height: 64px; font-size: 28px; cursor: pointer; border-radius: 8px; border: 1px solid #cbd5e1;"
        >{{ isUp(i) ? card.s : '?' }}</button>
      </div>
      <button (click)="reset()" style="margin-top: 14px; padding: 8px 16px; cursor: pointer;">New game</button>
    </div>
  `,
})
export class MemoryGameComponent {
  readonly symbols = ['🍎', '🚀', '🎲', '🎸', '🌵', '⚓'];
  deck: Card[] = this.makeDeck();
  flipped: number[] = [];
  matched = new Set<number>();
  lock = false;
  moves = 0;

  shuffle(arr: string[]): string[] {
    const a = arr.slice();
    for (let i = a.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      const t = a[i];
      a[i] = a[j];
      a[j] = t;
    }
    return a;
  }

  makeDeck(): Card[] {
    return this.shuffle([...this.symbols, ...this.symbols]).map((s, i) => ({ id: i, s }));
  }

  isUp(i: number): boolean {
    return this.flipped.indexOf(i) !== -1 || this.matched.has(i);
  }

  get won(): boolean {
    return this.matched.size === this.deck.length;
  }

  flip(i: number): void {
    if (this.lock || this.flipped.indexOf(i) !== -1 || this.matched.has(i)) {
      return;
    }
    this.flipped = [...this.flipped, i];
    if (this.flipped.length === 2) {
      this.moves++;
      const a = this.flipped[0];
      const b = this.flipped[1];
      if (this.deck[a].s === this.deck[b].s) {
        this.matched.add(a);
        this.matched.add(b);
        this.flipped = [];
      } else {
        this.lock = true;
        setTimeout(() => {
          this.flipped = [];
          this.lock = false;
        }, 800);
      }
    }
  }

  reset(): void {
    this.deck = this.makeDeck();
    this.flipped = [];
    this.matched = new Set();
    this.lock = false;
    this.moves = 0;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Memory Game Demo</h1>
      <app-memory-game></app-memory-game>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, MemoryGameComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
